// ── Configuration ─────────────────────────────────────────────
const IMAGE_NAME = env.get("NODE_RED_CONTAINER_NAME");
const TAG_DIR = env.get("NODE_RED_CONTAINER_DIRECTORY");
const TAG_FILE = `${TAG_DIR}/image:tag`;
// ──────────────────────────────────────────────────────────────

const now = new Date();
const curY = now.getFullYear();
const curM = now.getMonth() + 1;  // 1-12

let newTag;

if (!fs.existsSync(TAG_FILE)) {
    // File does not exist: create with YYYY.MM.1
    newTag = `${curY}.${curM}.1`;

} else {
    const content = fs.readFileSync(TAG_FILE, 'utf8').trim();
    // Expected format: imagename:YYYY.MM.patch
    const match = content.match(/:(\d+)\.(\d+)\.(\d+)$/);

    if (!match) {
        // Unreadable format: reset
        newTag = `${curY}.${curM}.1`;

    } else {
        let [, fileY, fileM, fileP] = match.map(Number);

        if (fileY === curY && fileM === curM) {
            // Same year and month: bump patch
            newTag = `${curY}.${curM}.${fileP + 1}`;

        } else {
            newTag = `${curY}.${curM}.1`;
        }
    }
}

const fileContent = `${IMAGE_NAME}:${newTag}`;
fs.writeFileSync(TAG_FILE, fileContent, 'utf8');

msg.payload = fileContent;
node.status({ fill: "green", shape: "dot", text: fileContent });
return msg;

const nodes = msg.redis;
const cluster = new redis.Cluster(nodes);

cluster.on('ready', async () => {
    try {
        // Only masters need keyspace notifications
        const allNodes = cluster.nodes('all');

        await Promise.all(
            allNodes.map(nodeConn =>
                nodeConn.config('SET', 'notify-keyspace-events', 'KEx')
                    .then(() => node.warn(
                        `Configured keyspace events on ${nodeConn.options.host}:${nodeConn.options.port}`
                    ))
                    .catch(err => node.error(
                        `Error configuring ${nodeConn.options.host}:${nodeConn.options.port}: ${err.message}`
                    ))
            )
        );

        msg.payload = true;
        await cluster.quit();
        node.send(msg);

    } catch (err) {
        node.error('Cluster configuration error: ' + err.message);
    }
});

cluster.on('error', (err) => {
    node.error('Cluster error: ' + err.message);
});

initialize:
if (!global.get('redisCluster')) {
    const redisUrl = env.get('REDIS_URL');
    const redisNodes = JSON.parse(redisUrl);

    // Create cluster with ioredis
    const cluster = new redis.Cluster(redisNodes);

    cluster.on('ready', () => {
        node.warn('Redis Cluster connected!');
        global.set('redisCluster', cluster);
    });

    cluster.on('error', (err) => {
        node.error('Cluster error: ' + err);
    });
}

