        const duration = ((Date.now() - startTime) / 1000).toFixed(2);

        node.status({
            fill: 'green',
            shape: 'dot',
            text: `Deleted ${stats.totalDeleted} keys`
        });

        msg.payload = {
            ...stats,
            duration: `${duration}s`,
            timestamp: new Date().toISOString()
        };

        node.send(msg);

        setTimeout(() => node.status({}), 5000);

    } catch (err) {
        node.status({ fill: 'red', shape: 'dot', text: 'Error' });
        node.error(`Cleanup failed: ${err.message}`);
        msg.payload = {
            error: err.message,
            stats: stats
        };
        node.send(msg);
    }
})();

