        const pattern = 'wis2gc:setup:*';
        const nodes = cluster.nodes('master');
        const allKeys = [];

        for (const node of nodes) {
            let cursor = '0';
            do {
                const [newCursor, keys] = await node.scan(cursor, 'MATCH', pattern, 'COUNT', 1000);
                cursor = newCursor;
                allKeys.push(...keys);
            } while (cursor !== '0');
        }

        const promises = allKeys.map(key => 
            cluster.hgetall(key)
                .then(value => value)
                .catch(err => {
                    node.warn(`Failed to HGETALL ${key}: ${err.message}`);
                    return null;
                })
        );

        const hashResults = await Promise.all(promises);
        const allTopics = [];

        for (const hashData of hashResults) {
            if (!hashData) continue;
            const arr = [];
            for (const [key, value] of Object.entries(hashData)) {
                arr.push(key, value);
            }
            for (let i = 0; i < arr.length; i += 2) {
                const key = arr[i];
                const value = arr[i + 1];
                if (key && key.endsWith(':subscriber')) {
                    try {
                        const parsed = JSON.parse(value);
                        if (Array.isArray(parsed)) {
                            if (parsed.length > 0 && typeof parsed[0] === 'object') {
                                // New format: array of {topic, qos} objects
                                parsed
                                    .filter(item => !item.topic.startsWith('replay/a/wis2'))
                                    .forEach(item => allTopics.push(item.topic));
                            } else {
                                // Old format: array of strings
                                parsed
                                    .filter(t => !t.startsWith('replay/a/wis2'))
                                    .forEach(t => allTopics.push(t));
                            }
                        }
                    } catch (e) {
                        node.warn(`Failed to parse subscriber value for ${key}: ${e.message}`);
                    }
                }
            }
        }

